package stream

import (
	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/config/shared"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/dataplane"
)

// Server holds all configuration for a stream server.
type Server struct {
	SSL             *SSL
	ProxySSLVerify  *ProxySSLVerify
	Listen          string
	StatusZone      string
	ProxyPass       string
	Target          string
	RewriteClientIP shared.RewriteClientIPSettings
	SSLPreread      bool
	IsSocket        bool
}

// ProxySSLVerify holds backend TLS verification settings for stream proxying.
type ProxySSLVerify struct {
	TrustedCertificate string
	Name               string
}

// SSL holds SSL configuration for a stream server performing TLS termination.
type SSL struct {
	Protocols           string
	Ciphers             string
	Certificates        []string
	CertificateKeys     []string
	PreferServerCiphers bool
	RejectHandshake     bool
}

// Upstream holds all configuration for a stream upstream.
type Upstream struct {
	Name      string
	ZoneSize  string // format: 512k, 1m
	StateFile string
	Servers   []UpstreamServer
}

// UpstreamServer holds all configuration for a stream upstream server.
type UpstreamServer struct {
	Address string
	Resolve bool
	Weight  int32 // Weight for load balancing, default 1
}

// SplitClient holds configuration for a stream split_clients directive.
type SplitClient struct {
	VariableName  string
	Distributions []SplitClientDistribution
}

// SplitClientDistribution holds configuration for a split_clients distribution.
type SplitClientDistribution struct {
	Percent string
	Value   string
}

// ServerConfig holds configuration for a stream server and IP family to be used by NGINX.
type ServerConfig struct {
	DNSResolver     *dataplane.DNSResolverConfig
	GatewaySecretID dataplane.SSLKeyPairID
	Servers         []Server
	SplitClients    []SplitClient
	IPFamily        shared.IPFamily
	Plus            bool
}

