1	package config
2	
3	import (
4		"fmt"
5		"slices"
6		"sort"
7		"strconv"
8		"strings"
9		gotemplate "text/template"
10	
11		inference "sigs.k8s.io/gateway-api-inference-extension/api/v1"
12	
13		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/config/shared"
14		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/dataplane"
15		"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/helpers"
16	)
17	
18	var mapsTemplate = gotemplate.Must(gotemplate.New("maps").Parse(mapsTemplateText))
19	
20	const (
21		// emptyStringSocket is used when the stream server has an invalid upstream. In this case, we pass the connection
22		// to the empty socket so that NGINX will close the connection with an error in the error log --
23		// no host in pass "" -- and set $status variable to 500 (logged by stream access log),
24		// which will indicate the problem to the user.
25		// https://nginx.org/en/docs/stream/ngx_stream_core_module.html#var_status
26		emptyStringSocket = `""`
27	
28		// connectionClosedStreamServerSocket is used when we want to listen on a port but have no service configured,
29		// so we pass to this server that just returns an empty string to tell users that we are listening.
30		connectionClosedStreamServerSocket = SocketBasePath + "connection-closed-server.sock"
31	)
32	
33	func executeMaps(conf dataplane.Configuration) []executeResult {
34		httpAndSSLServers := make([]dataplane.VirtualServer, 0, len(conf.HTTPServers)+len(conf.SSLServers))
35		httpAndSSLServers = append(httpAndSSLServers, conf.HTTPServers...)
36		httpAndSSLServers = append(httpAndSSLServers, conf.SSLServers...)
37	
38		maps := buildAddHeaderMaps(httpAndSSLServers)
39		maps = append(maps, buildInferenceMaps(conf.BackendGroups)...)
40		maps = append(maps, buildCorsMaps(conf.HTTPServers, conf.SSLServers)...)
41	
42		if !conf.BaseHTTPConfig.DisableSNIHostValidation {
43			maps = append(maps, buildMisdirectedRequestMaps(conf.SSLListenerHostnames)...)
44		}
45	
46		result := executeResult{
47			dest: httpConfigFile,
48			data: helpers.MustExecuteTemplate(mapsTemplate, maps),
49		}
50	
51		return []executeResult{result}
52	}
53	
54	func buildCorsMaps(httpServers, sslServers []dataplane.VirtualServer) []shared.Map {
55		originMaps := make([]shared.Map, 0)
56	
57		for serverIndex, s := range httpServers {
58			serverID := fmt.Sprintf("%d", serverIndex)
59			originMaps = append(originMaps, buildCorsMapsForServer(s, serverID)...)
60		}
61	
62		for serverIndex, s := range sslServers {
63			serverID := fmt.Sprintf("SSL_%d", serverIndex)
64			originMaps = append(originMaps, buildCorsMapsForServer(s, serverID)...)
65		}
66	
67		return originMaps
68	}
69	
70	func buildCorsMapsForServer(s dataplane.VirtualServer, serverID string) []shared.Map {
71		originMaps := make([]shared.Map, 0)
72	
73		for pathRuleIndex, pr := range s.PathRules {
74			for matchRuleIndex, mr := range pr.MatchRules {
75				if mr.Filters.CORSFilter != nil {
76					corsFilter := mr.Filters.CORSFilter
77					if corsFilter.AllowOrigins != nil {
78						nginxVar := generateCORSAllowedOriginVariableName(serverID, pathRuleIndex, matchRuleIndex)
79						originMaps = append(originMaps, shared.Map{
80							Source:     "$http_origin",
81							Variable:   nginxVar,
82							Parameters: buildCORSOriginMapParameters(corsFilter.AllowOrigins),
83						})
84					}
85					if corsFilter.AllowCredentials {
86						nginxVar := generateCORSAllowCredentialsVariableName(serverID, pathRuleIndex, matchRuleIndex)
87						originMaps = append(originMaps, shared.Map{
88							Source:     "$http_origin",
89							Variable:   nginxVar,
90							Parameters: buildCORSAllowCredentialsMapParameters(corsFilter.AllowOrigins),
91						})
92					}
93				}
94			}
95		}
96	
97		return originMaps
98	}
99	
100	func buildCORSAllowCredentialsMapParameters(s []string) []shared.MapParameter {
101		params := make([]shared.MapParameter, 0, len(s))
102	
103		for _, origin := range s {
104			params = append(params, shared.MapParameter{
105				Value:  convertToNginxRegex(origin),
106				Result: "true",
107			})
108		}
109	
110		return params
111	}
112	
113	func buildCORSOriginMapParameters(s []string) []shared.MapParameter {
114		params := make([]shared.MapParameter, 0, len(s))
115	
116		for _, origin := range s {
117			params = append(params, shared.MapParameter{
118				Value:  convertToNginxRegex(origin),
119				Result: "$http_origin",
120			})
121		}
122	
123		return params
124	}
125	
126	func convertToNginxRegex(input string) string {
127		return "\"~^" + strings.ReplaceAll(strings.ReplaceAll(input, ".", "\\."), "*", ".*") + "$\""
128	}
129	
130	func executeStreamMaps(conf dataplane.Configuration) []executeResult {
131		maps := createStreamMaps(conf)
132	
133		result := executeResult{
134			dest: streamConfigFile,
135			data: helpers.MustExecuteTemplate(mapsTemplate, maps),
136		}
137	
138		return []executeResult{result}
139	}
140	
141	func createStreamMaps(conf dataplane.Configuration) []shared.Map {
142		if len(conf.TLSServers) == 0 {
143			return nil
144		}
145		portsToMap := make(map[int32]shared.Map)
146		portHasDefault := make(map[int32]struct{})
147		upstreams := make(map[string]dataplane.Upstream)
148	
149		for _, u := range conf.StreamUpstreams {
150			upstreams[u.Name] = u
151		}
152	
153		for _, server := range conf.TLSServers {
154			addTLSServerToStreamMap(server, upstreams, portsToMap, portHasDefault)
155		}
156	
157		for _, server := range conf.SSLServers {
158			streamMap, portInUse := portsToMap[server.Port]
159	
160			hostname := server.Hostname
161	
162			if server.IsDefault {
163				hostname = "default"
164				portHasDefault[server.Port] = struct{}{}
165			}
166	
167			if portInUse {
168				streamMap.Parameters = append(streamMap.Parameters, shared.MapParameter{
169					Value:  hostname,
170					Result: getSocketNameHTTPS(server.Port),
171				})
172				portsToMap[server.Port] = streamMap
173			}
174		}
175	
176		maps := make([]shared.Map, 0, len(portsToMap))
177	
178		for p, m := range portsToMap {
179			if _, ok := portHasDefault[p]; !ok {
180				m.Parameters = append(m.Parameters, shared.MapParameter{
181					Value:  "default",
182					Result: connectionClosedStreamServerSocket,
183				})
184			}
185			maps = append(maps, m)
186		}
187	
188		return maps
189	}
190	
191	// addTLSServerToStreamMap adds a TLS server entry to the stream map for its port,
192	// resolving the appropriate socket name based on mode (passthrough vs terminate) and state.
193	func addTLSServerToStreamMap(
194		server dataplane.Layer4VirtualServer,
195		upstreams map[string]dataplane.Upstream,
196		portsToMap map[int32]shared.Map,
197		portHasDefault map[int32]struct{},
198	) {
199		streamMap, portInUse := portsToMap[server.Port]
200	
201		socket := resolveTLSServerSocket(server, upstreams)
202	
203		if !portInUse {
204			streamMap = shared.Map{
205				Source:       "$ssl_preread_server_name",
206				Variable:     getTLSPassthroughVarName(server.Port),
207				Parameters:   make([]shared.MapParameter, 0),
208				UseHostnames: true,
209			}
210		}
211	
212		if server.IsDefault && server.SSL != nil && server.Hostname == "" {
213			if _, hasDefault := portHasDefault[server.Port]; !hasDefault {
214				// Only an unnamed TLS Terminate default server should claim the map's
215				// port-level default entry. This preserves the catch-all behavior for
216				// requests without SNI while avoiding multiple "default" parameters for
217				// the same port when another listener type also provides a default.
218				streamMap.Parameters = append(streamMap.Parameters, shared.MapParameter{
219					Value:  "default",
220					Result: socket,
221				})
222				portHasDefault[server.Port] = struct{}{}
223			}
224		}
225	
226		if server.Hostname != "" {
227			streamMap.Parameters = append(streamMap.Parameters, shared.MapParameter{
228				Value:  server.Hostname,
229				Result: socket,
230			})
231		}
232	
233		portsToMap[server.Port] = streamMap
234	}
235	
236	// resolveTLSServerSocket determines the socket path for a TLS server entry in the stream map.
237	func resolveTLSServerSocket(
238		server dataplane.Layer4VirtualServer,
239		upstreams map[string]dataplane.Upstream,
240	) string {
241		if server.IsDefault {
242			if server.SSL != nil {
243				return getSocketNameTLSTerminate(server.Port, server.Hostname)
244			}
245			return connectionClosedStreamServerSocket
246		}
247	
248		if len(server.Upstreams) > 0 {
249			upstreamName := server.Upstreams[0].Name
250			if u, ok := upstreams[upstreamName]; ok && len(u.Endpoints) > 0 {
251				if server.SSL != nil {
252					return getSocketNameTLSTerminate(server.Port, server.Hostname)
253				}
254				return getSocketNameTLS(server.Port, server.Hostname)
255			}
256		}
257	
258		return emptyStringSocket
259	}
260	
261	// buildMisdirectedRequestMaps creates per-port maps that resolve both $ssl_server_name and $host
262	// to a listener group ID. This is used to detect misdirected HTTPS requests per the Gateway API spec.
263	// When SNI and Host resolve to different listener groups, the server returns 421 Misdirected Request.
264	func buildMisdirectedRequestMaps(hostnamesByPort map[int32][]string) []shared.Map {
265		if len(hostnamesByPort) == 0 {
266			return nil
267		}
268	
269		// Sort ports for deterministic output.
270		ports := make([]int32, 0, len(hostnamesByPort))
271		for port := range hostnamesByPort {
272			ports = append(ports, port)
273		}
274		slices.Sort(ports)
275	
276		maps := make([]shared.Map, 0, len(ports)*2)
277	
278		for _, port := range ports {
279			hostnames := hostnamesByPort[port]
280	
281			// Sort hostnames for deterministic output.
282			sorted := make([]string, len(hostnames))
283			copy(sorted, hostnames)
284			sort.Strings(sorted)
285	
286			// Assign each unique listener hostname a listener ID, starting from 1.
287			// ID 0 is reserved for the "default" entry (catch-all / empty listener).
288			params := make([]shared.MapParameter, 0, len(sorted)+1)
289			nextID := 1
290	
291			for _, h := range sorted {
292				if h == "" {
293					continue
294				}
295				params = append(params, shared.MapParameter{
296					Value:  h,
297					Result: strconv.Itoa(nextID),
298				})
299				nextID++
300			}
301	
302			// The default entry represents either an explicit empty-hostname listener
303			// or the fallback for unmatched hostnames. In both cases, ID is "0".
304			params = append(params, shared.MapParameter{
305				Value:  "default",
306				Result: "0",
307			})
308	
309			sniMap := shared.Map{
310				Source:       "$ssl_server_name",
311				Variable:     misdirectedRequestSNIVar(port),
312				Parameters:   params,
313				UseHostnames: true,
314			}
315	
316			hostMap := shared.Map{
317				Source:       "$host",
318				Variable:     misdirectedRequestHostVar(port),
319				Parameters:   params,
320				UseHostnames: true,
321			}
322	
323			maps = append(maps, sniMap, hostMap)
324		}
325	
326		return maps
327	}
328	
329	func buildAddHeaderMaps(servers []dataplane.VirtualServer) []shared.Map {
330		addHeaderNames := make(map[string]struct{})
331	
332		for _, s := range servers {
333			for _, pr := range s.PathRules {
334				for _, mr := range pr.MatchRules {
335					if mr.Filters.RequestHeaderModifiers != nil {
336						for _, addHeader := range mr.Filters.RequestHeaderModifiers.Add {
337							lowerName := strings.ToLower(addHeader.Name)
338							if _, ok := addHeaderNames[lowerName]; !ok {
339								addHeaderNames[lowerName] = struct{}{}
340							}
341						}
342					}
343				}
344			}
345		}
346	
347		// Sort the names so that the maps are emitted in a stable order and identical
348		// input doesn't trigger an unnecessary reload.
349		names := make([]string, 0, len(addHeaderNames))
350		for m := range addHeaderNames {
351			names = append(names, m)
352		}
353		sort.Strings(names)
354	
355		maps := make([]shared.Map, 0, len(names))
356		for _, m := range names {
357			maps = append(maps, createAddHeadersMap(m))
358		}
359		return maps
360	}
361	
362	const (
363		// In order to prepend any passed client header values to values specified in the add headers field of request
364		// header modifiers, we need to create a map parameter regex for any string value.
365		anyStringFmt = `~.*`
366	)
367	
368	func createAddHeadersMap(name string) shared.Map {
369		underscoreName := convertStringToSafeVariableName(name)
370		httpVarSource := "${http_" + underscoreName + "}"
371		mapVarName := generateAddHeaderMapVariableName(name)
372		params := []shared.MapParameter{
373			{
374				Value:  "default",
375				Result: "''",
376			},
377			{
378				Value:  anyStringFmt,
379				Result: httpVarSource + ",",
380			},
381		}
382		return shared.Map{
383			Source:     httpVarSource,
384			Variable:   "$" + mapVarName,
385			Parameters: params,
386		}
387	}
388	
389	// buildInferenceMaps creates maps for InferencePool Backends.
390	func buildInferenceMaps(groups []dataplane.BackendGroup) []shared.Map {
391		uniqueMaps := make(map[string]shared.Map)
392	
393		for _, group := range groups {
394			for _, backend := range group.Backends {
395				if backend.EndpointPickerConfig == nil || backend.EndpointPickerConfig.EndpointPickerRef == nil {
396					continue
397				}
398	
399				backendVarName := strings.ReplaceAll(backend.UpstreamName, "-", "_")
400				mapKey := backendVarName // Use this as the key to detect duplicates
401	
402				// Skip if we've already processed this upstream
403				if _, exists := uniqueMaps[mapKey]; exists {
404					continue
405				}
406				// Decide what the map must return when the picker didn’t set a value.
407				var defaultResult string
408				switch backend.EndpointPickerConfig.EndpointPickerRef.FailureMode {
409				// in FailClose mode, if the EPP is unavailable or returns an error,
410				// we return an invalid backend to ensure the request fails
411				case inference.EndpointPickerFailClose:
412					defaultResult = invalidBackendRef
413	
414				// in FailOpen mode, if the EPP is unavailable or returns an error,
415				// we fall back to the upstream
416				case inference.EndpointPickerFailOpen:
417					defaultResult = backend.UpstreamName
418				}
419	
420				// Build the ordered parameter list.
421				params := make([]shared.MapParameter, 0, 3)
422	
423				// no endpoint picked by EPP go to inference pool directly
424				params = append(params, shared.MapParameter{
425					Value:  `""`,
426					Result: backend.UpstreamName,
427				})
428	
429				// endpoint picked by the EPP is stored in $inference_workload_endpoint.
430				params = append(params, shared.MapParameter{
431					Value:  `~.+`,
432					Result: `$inference_workload_endpoint`,
433				})
434	
435				// this is set based on EPP failure mode,
436				// if EPP is failOpen, we set the default to the inference pool upstream,
437				// if EPP is failClose, we set the default to invalidBackendRef.
438				params = append(params, shared.MapParameter{
439					Value:  "default",
440					Result: defaultResult,
441				})
442	
443				uniqueMaps[mapKey] = shared.Map{
444					Source:     `$inference_workload_endpoint`,
445					Variable:   fmt.Sprintf("$inference_backend_%s", backendVarName),
446					Parameters: params,
447				}
448			}
449		}
450	
451		// Sort the map keys to ensure deterministic ordering
452		mapKeys := make([]string, 0, len(uniqueMaps))
453		for key := range uniqueMaps {
454			mapKeys = append(mapKeys, key)
455		}
456		sort.Strings(mapKeys)
457	
458		// Build the result slice in sorted order
459		inferenceMaps := make([]shared.Map, 0, len(uniqueMaps))
460		for _, key := range mapKeys {
461			inferenceMaps = append(inferenceMaps, uniqueMaps[key])
462		}
463	
464		return inferenceMaps
465	}
