1	package config
2	
3	import (
4		"fmt"
5		gotemplate "text/template"
6	
7		ngfAPI "github.com/nginx/nginx-gateway-fabric/v2/apis/v1alpha1"
8		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/config/http"
9		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/config/policies/upstreamsettings"
10		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/config/stream"
11		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/types"
12		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/dataplane"
13		"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/helpers"
14	)
15	
16	var (
17		upstreamsTemplate       = gotemplate.Must(gotemplate.New("upstreams").Parse(upstreamsTemplateText))
18		streamUpstreamsTemplate = gotemplate.Must(gotemplate.New("streamUpstreams").Parse(streamUpstreamsTemplateText))
19	)
20	
21	const (
22		// nginx500Server is used as a server for the invalid backend ref upstream.
23		nginx500Server = SocketBasePath + "nginx-500-server.sock"
24		// invalidBackendRef is used as an upstream name for invalid backend references.
25		invalidBackendRef = "invalid-backend-ref"
26		// ossZoneSize is the upstream zone size for nginx open source.
27		ossZoneSize = "512k"
28		// plusZoneSize is the upstream zone size for nginx plus.
29		plusZoneSize = "1m"
30		// ossZoneSize is the upstream zone size for nginx open source.
31		ossZoneSizeStream = "512k"
32		// plusZoneSize is the upstream zone size for nginx plus.
33		plusZoneSizeStream = "1m"
34		// stateDir is the directory for storing state files.
35		stateDir = "/var/lib/nginx/state"
36		// default load balancing method.
37		defaultLBMethod = "random two least_conn"
38	)
39	
40	// keepAliveChecker takes an upstream name and returns if it has keep alive settings enabled.
41	type keepAliveChecker func(upstreamName string) bool
42	
43	func newKeepAliveChecker(upstreams []http.Upstream) keepAliveChecker {
44		upstreamMap := make(map[string]http.Upstream)
45	
46		for _, upstream := range upstreams {
47			upstreamMap[upstream.Name] = upstream
48		}
49	
50		return func(upstreamName string) bool {
51			if upstream, exists := upstreamMap[upstreamName]; exists {
52				return upstream.KeepAlive.Connections != nil && *upstream.KeepAlive.Connections > 0
53			}
54	
55			return false
56		}
57	}
58	
59	func newExecuteUpstreamsFunc(upstreams []http.Upstream) executeFunc {
60		return func(_ dataplane.Configuration) []executeResult {
61			return executeUpstreams(upstreams)
62		}
63	}
64	
65	func executeUpstreams(upstreams []http.Upstream) []executeResult {
66		result := executeResult{
67			dest: httpConfigFile,
68			data: helpers.MustExecuteTemplate(upstreamsTemplate, upstreams),
69		}
70	
71		return []executeResult{result}
72	}
73	
74	func (g GeneratorImpl) executeStreamUpstreams(conf dataplane.Configuration) []executeResult {
75		upstreams := g.createStreamUpstreams(conf.StreamUpstreams)
76	
77		result := executeResult{
78			dest: streamConfigFile,
79			data: helpers.MustExecuteTemplate(streamUpstreamsTemplate, upstreams),
80		}
81	
82		return []executeResult{result}
83	}
84	
85	func (g GeneratorImpl) createStreamUpstreams(upstreams []dataplane.Upstream) []stream.Upstream {
86		ups := make([]stream.Upstream, 0, len(upstreams))
87	
88		for _, u := range upstreams {
89			if len(u.Endpoints) != 0 {
90				ups = append(ups, g.createStreamUpstream(u))
91			}
92		}
93	
94		return ups
95	}
96	
97	func (g GeneratorImpl) createStreamUpstream(up dataplane.Upstream) stream.Upstream {
98		var stateFile string
99		zoneSize := ossZoneSizeStream
100		if g.plus {
101			zoneSize = plusZoneSizeStream
102			// Only set state file if the upstream doesn't have resolve servers
103			// Upstreams with resolve servers can't be managed via NGINX Plus API
104			if !upstreamHasResolveServers(up) {
105				stateFile = fmt.Sprintf("%s/%s.conf", stateDir, up.Name)
106			}
107		}
108	
109		upstreamServers := make([]stream.UpstreamServer, len(up.Endpoints))
110		for idx, ep := range up.Endpoints {
111			format := "%s:%d"
112			if ep.IPv6 {
113				format = "[%s]:%d"
114			}
115			// Keep the original weight from endpoint
116			// For single backend: Weight is 0 (template won't output weight directive)
117			// For multi-backend: Weight is set from BackendRef.Weight (template outputs weight=X if > 1)
118			upstreamServers[idx] = stream.UpstreamServer{
119				Address: fmt.Sprintf(format, ep.Address, ep.Port),
120				Resolve: ep.Resolve,
121				Weight:  ep.Weight,
122			}
123		}
124	
125		return stream.Upstream{
126			Name:      up.Name,
127			ZoneSize:  zoneSize,
128			StateFile: stateFile,
129			Servers:   upstreamServers,
130		}
131	}
132	
133	func (g GeneratorImpl) createUpstreams(
134		upstreams []dataplane.Upstream,
135		processor upstreamsettings.Processor,
136	) []http.Upstream {
137		// capacity is the number of upstreams + 1 for the invalid backend ref upstream
138		ups := make([]http.Upstream, 0, len(upstreams)+1)
139	
140		for _, u := range upstreams {
141			ups = append(ups, g.createUpstream(u, processor))
142		}
143	
144		ups = append(ups, createInvalidBackendRefUpstream())
145	
146		return ups
147	}
148	
149	func (g GeneratorImpl) createUpstream(
150		up dataplane.Upstream,
151		processor upstreamsettings.Processor,
152	) http.Upstream {
153		var stateFile string
154		var sp http.UpstreamSessionPersistence
155		upstreamPolicySettings := processor.Process(up.Policies)
156	
157		zoneSize := ossZoneSize
158		if g.plus {
159			zoneSize = plusZoneSize
160			// Only set state file if the upstream doesn't have resolve servers
161			// Upstreams with resolve servers can't be managed via NGINX Plus API
162			if !upstreamHasResolveServers(up) {
163				base := up.StateFileKey
164				if base == "" {
165					base = up.Name
166				}
167				stateFile = fmt.Sprintf("%s/%s.conf", stateDir, base)
168			}
169	
170			sp = getSessionPersistenceConfiguration(up.SessionPersistence)
171		}
172	
173		if upstreamPolicySettings.ZoneSize != "" {
174			zoneSize = upstreamPolicySettings.ZoneSize
175		}
176	
177		chosenLBMethod := defaultLBMethod
178		if upstreamPolicySettings.LoadBalancingMethod != "" {
179			lbMethod := upstreamPolicySettings.LoadBalancingMethod
180	
181			if lbMethod == string(ngfAPI.LoadBalancingTypeHash) {
182				lbMethod = fmt.Sprintf("hash %s", upstreamPolicySettings.HashMethodKey)
183			}
184			if lbMethod == string(ngfAPI.LoadBalancingTypeHashConsistent) {
185				lbMethod = fmt.Sprintf("hash %s consistent", upstreamPolicySettings.HashMethodKey)
186			}
187			if lbMethod == string(ngfAPI.LoadBalancingTypeRoundRobin) {
188				lbMethod = ""
189			}
190			chosenLBMethod = lbMethod
191		}
192	
193		keepAliveSettings := processKeepAliveSettings(upstreamPolicySettings.KeepAlive)
194		if len(up.Endpoints) == 0 {
195			return http.Upstream{
196				Name:      up.Name,
197				ZoneSize:  zoneSize,
198				StateFile: stateFile,
199				Servers: []http.UpstreamServer{
200					{
201						Address: types.Nginx503Server,
202					},
203				},
204				LoadBalancingMethod: chosenLBMethod,
205				KeepAlive:           keepAliveSettings,
206			}
207		}
208	
209		upstreamServers := make([]http.UpstreamServer, len(up.Endpoints))
210		for idx, ep := range up.Endpoints {
211			format := "%s:%d"
212			if ep.IPv6 {
213				format = "[%s]:%d"
214			}
215			upstreamServers[idx] = http.UpstreamServer{
216				Address: fmt.Sprintf(format, ep.Address, ep.Port),
217				Resolve: ep.Resolve,
218			}
219		}
220	
221		return http.Upstream{
222			Name:                up.Name,
223			ZoneSize:            zoneSize,
224			StateFile:           stateFile,
225			Servers:             upstreamServers,
226			KeepAlive:           keepAliveSettings,
227			LoadBalancingMethod: chosenLBMethod,
228			SessionPersistence:  sp,
229		}
230	}
231	
232	// processKeepAliveSettings normalizes keepalive configuration from an upstream policy.
233	// If Connections is nil, it's set to the default value of 16.
234	// If Connections is set to 0, it indicates that keepAlive is disabled.
235	func processKeepAliveSettings(spec http.UpstreamKeepAlive) http.UpstreamKeepAlive {
236		if spec.Connections == nil {
237			spec.Connections = helpers.GetPointer[int32](http.KeepAliveConnectionDefault)
238		}
239	
240		if spec.Connections != nil && *spec.Connections == 0 {
241			return http.UpstreamKeepAlive{
242				Requests: spec.Requests,
243				Time:     spec.Time,
244				Timeout:  spec.Timeout,
245			}
246		}
247	
248		return spec
249	}
250	
251	func createInvalidBackendRefUpstream() http.Upstream {
252		// ZoneSize is omitted since we will only ever proxy to one destination/backend.
253		return http.Upstream{
254			Name: invalidBackendRef,
255			Servers: []http.UpstreamServer{
256				{
257					Address: nginx500Server,
258				},
259			},
260		}
261	}
262	
263	// upstreamHasResolveServers checks if an upstream contains servers that require DNS resolution.
264	func upstreamHasResolveServers(upstream dataplane.Upstream) bool {
265		for _, endpoint := range upstream.Endpoints {
266			if endpoint.Resolve {
267				return true
268			}
269		}
270		return false
271	}
272	
273	// getSessionPersistenceConfiguration gets the session persistence configuration for an upstream.
274	// Supported only for NGINX Plus and cookie-based type.
275	func getSessionPersistenceConfiguration(sp dataplane.SessionPersistenceConfig) http.UpstreamSessionPersistence {
276		if sp.Name == "" {
277			return http.UpstreamSessionPersistence{}
278		}
279		return http.UpstreamSessionPersistence{
280			Name:        sp.Name,
281			Expiry:      sp.Expiry,
282			Path:        sp.Path,
283			SessionType: string(sp.SessionType),
284		}
285	}
